if( ! function_exists( 'hongo_addons_add_template_content' ) ) {

	function hongo_addons_add_template_content( $template, $template_content ) {

		$template_content = str_replace( HONGO_ADDONS_DEMO_URI . 'demo-images', HONGO_ADDONS_DEMO_IMAGES_URI, $template_content );

		$template['content'] = <<<CONTENT
		{$template_content}
CONTENT;

		return $template;
	}
}

